import type { FC } from 'react';
import React from 'react';
import type { SingleSelectProps } from '../select';
import { Select } from '../select';

const WrapperSelect: FC<SingleSelectProps<any>> = ({ ...props }) => (
  <Select {...props} size="small" allowClear={false} virtual={false} />
);

export const PaginationSelect = Object.assign(WrapperSelect, {
  Option: Select.Option,
});
